class Pessoa:
    def __init__(self, nome):
        self.nome = nome
    def falar(self):
        print(f'Olá, sou {self.nome}')

class Estudante(Pessoa):
    def __init__(self, nome, curso):
        super().__init__(nome)
        self.curso = curso - herança

@dataclass
class Ponto:
    x: int
    y: int - dataclass (Python 3.7+)

def fibonacci():
    a, b = 0, 1
    while True:
        yield a
        a, b = b, a + b - generator function
